import{_ as t,o as a,c as o,a2 as i}from"./chunks/framework.B8zgMDLd.js";const u=JSON.parse('{"title":"AI","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/ai.md","filePath":"concepts/ai.md"}'),n={name:"concepts/ai.md"};function r(s,e,l,d,c,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="ai" tabindex="-1">AI <a class="header-anchor" href="#ai" aria-label="Permalink to &quot;AI&quot;">​</a></h1><p>Tolaria has two AI paths: coding agents that can use tools to inspect and edit a vault, and direct model targets that answer in chat mode from note context.</p><h2 id="coding-agents" tabindex="-1">Coding Agents <a class="header-anchor" href="#coding-agents" aria-label="Permalink to &quot;Coding Agents&quot;">​</a></h2><p>The AI panel can stream supported local CLI agents through Tolaria&#39;s normalized event layer. Current targets include Claude Code, Codex, OpenCode, Pi, and Gemini CLI when they are installed on the machine.</p><p>Coding agents can run in:</p><ul><li><strong>Vault Safe</strong> mode, limited to file, search, and edit tools.</li><li><strong>Power User</strong> mode, which can allow local shell commands scoped to the active vault for agents that support shell access.</li></ul><h2 id="direct-models" tabindex="-1">Direct Models <a class="header-anchor" href="#direct-models" aria-label="Permalink to &quot;Direct Models&quot;">​</a></h2><p>Direct model targets run in chat mode. They receive the active note, linked context, and conversation history, but they do not receive vault-write tools or shell access.</p><p>Supported provider shapes include:</p><ul><li>Local models through Ollama or LM Studio.</li><li>Hosted providers such as OpenAI, Anthropic, Gemini, and OpenRouter.</li><li>Custom OpenAI-compatible endpoints.</li></ul><h2 id="external-mcp-setup" tabindex="-1">External MCP Setup <a class="header-anchor" href="#external-mcp-setup" aria-label="Permalink to &quot;External MCP Setup&quot;">​</a></h2><p>Tolaria exposes an MCP server for external tools. The setup flow can write Tolaria&#39;s MCP entry into Claude Code, Gemini CLI, Cursor, and a generic MCP config path, and it can also copy the exact JSON snippet for manual setup.</p><p>MCP setup is explicit. Closing the dialog leaves third-party config files untouched.</p><h2 id="why-git-matters-for-ai" tabindex="-1">Why Git Matters For AI <a class="header-anchor" href="#why-git-matters-for-ai" aria-label="Permalink to &quot;Why Git Matters For AI&quot;">​</a></h2><p>AI-generated changes should be inspectable. Git gives you diffs, history, rollback, and a clear boundary between suggestions and committed work.</p>',15)])])}const m=t(n,[["render",r]]);export{u as __pageData,m as default};
